import React from 'react';
import * as Styled from './styles';
import { useInView } from 'react-intersection-observer';
import useMobile from '../../helpers/hooks/useMobile';
import useTablet from '../../helpers/hooks/useTablet';
// import { useNavigate } from 'react-router-dom';

const PortfolioCard = ({image, title, description, link}) => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
    const isMobile = useMobile();
    const isTablet = useTablet();
    // const navigate = useNavigate();
    
    return (
        <Styled.Card
            isTablet={isTablet}
            ref={ref}
            inView={inView}
            isMobile={isMobile}
            // onClick={()=> navigate(`/portfolio/${link}`)}
        >
            <Styled.ImageContainer>
                <Styled.CardImage src={image} />
            </Styled.ImageContainer>
            <Styled.CardTitle>{title}</Styled.CardTitle>
            <Styled.CardDescription>{description}</Styled.CardDescription>
        </Styled.Card>
    );
};

export default PortfolioCard;