import React, { useState, useMemo, useRef } from 'react';
import { DarkSubTitle } from '../../../styles/common';
import * as Styled from './styles';
import { useInView } from 'react-intersection-observer';
import useMobile from '../../../helpers/hooks/useMobile';
import useTablet from '../../../helpers/hooks/useTablet';
import CassianOpara from '../../../assets/images/Partners/CassianOpara.svg';
import NellyRinot from '../../../assets/images/Partners/NellyRinot.svg';
import EliLavi from '../../../assets/images/Partners/ElliLavi.svg';
import {ReactComponent as LongArrow} from '../../../assets/images/longArrow.svg'

const TestimonialsSection = () => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
    const isTablet = useTablet();
    const [currentTestimonial, setCurrentTestimonial] = useState(0);
    const leftButtonRef = useRef();
    const rightButtonRef = useRef();

    const tabInfo = useMemo(() => [{
        avatar: CassianOpara,
        name: 'Cassian Opara',
        position: 'Founder of Makette',
        quote: 'We have worked with Jito on several projects and they have proven to be reliable, fast without being sloppy, and always go that extra mile to help our team ship great products. I would highly recommend them to clients looking for a fast turnaround without sacrificing quality.',
    },{
        avatar: NellyRinot,
        name: 'Nelly Rinot',
        position: 'Founder of Marketer',
        quote: `We thought we had a good product design until we saw Anastasiia's improvements. The designs became slicker and user-friendly. She was able to fast-track our design so much that we completed our design roadmap within weeks. I was impressed by her level of expertise, work ethic, and excellent team management.`,
    },{
        avatar: EliLavi,
        name: 'Eli Lavi',
        position: 'CEO and Co-founder of GeoX',
        quote: 'Jito is a great web development company. They do everything we need done, always on-time and the work is of superior quality. We use them for most of our web projects now, would recommend to anyone looking for excellent service.',
    }],[]);

    function onButtonCLick (action,reference) {
        // reset animation
        if ( reference.current.classList.contains('changing')) {
            reference.current.classList.remove('changing');
        }
        window.requestAnimationFrame(function(time) {
            window.requestAnimationFrame(function(time) {
                reference.current.classList.add('changing');
            });
          });

        if (action === 'plus') {
            currentTestimonial >= tabInfo.length - 1 ? setCurrentTestimonial(0) : setCurrentTestimonial(currentTestimonial + 1);
        } else {
            currentTestimonial <= 0 ? setCurrentTestimonial(tabInfo.length - 1) : setCurrentTestimonial(currentTestimonial - 1);
        }
    }

    const currentQuote = document.querySelectorAll('.quote-card')[1];

    return (
        <Styled.SectionContainer>
            <Styled.TestimonialsSection isTablet={isTablet} isMobile={isMobile} inView={inView} ref={ref}>
                <DarkSubTitle>What they say about us</DarkSubTitle>
                <Styled.CardContainer style={{marginBottom: currentQuote?.offsetHeight - 48 + 'px' }}>
                    <Styled.ButtonsContainer>
                        <Styled.LeftSliderButton
                            data-ccursor
                            ref={leftButtonRef}
                            onClick={() => onButtonCLick('plus',leftButtonRef)}
                            className='changing'
                        >
                            <LongArrow/>
                        </Styled.LeftSliderButton>
                        <Styled.RightSliderButton
                            data-ccursor
                            ref={rightButtonRef}
                            className='changing'
                            onClick={() => onButtonCLick('minus',rightButtonRef)}
                        >
                            <LongArrow/>
                        </Styled.RightSliderButton>
                    </Styled.ButtonsContainer>
                {tabInfo.map((item, index) => {
                    const isActive = index === currentTestimonial ? true : false;
                    return (
                        <Styled.Card className='quote-card' isActive={isActive} key={index}>
                        <Styled.CardHeader>
                            <Styled.AuthorContainer>
                                <Styled.AuthorAvatarContainer>
                                    <Styled.AuthorAvatar image={item.avatar} />
                                </Styled.AuthorAvatarContainer>
                                <Styled.AuthorInfo>
                                    <Styled.AuthorName>{item.name}</Styled.AuthorName>
                                    <Styled.AuthorPosition>{item.position}</Styled.AuthorPosition>
                                </Styled.AuthorInfo>
                            </Styled.AuthorContainer>
                        </Styled.CardHeader>
                        <Styled.AuthorQuote>{item.quote}</Styled.AuthorQuote>
                    </Styled.Card>
                    )
                })}
                </Styled.CardContainer>
            </Styled.TestimonialsSection>          
        </Styled.SectionContainer>
    );
};

export default TestimonialsSection;