import styled from 'styled-components';
import doubleOptions from '../../helpers/functions/doubleOptions';

export const CardImage = styled.img``;

export const CardTitle = styled.p``;

export const CardDescription = styled.p``;

export const ImageContainer = styled.div`
    width: 100%;
    box-sizing: border-box;
    overflow: hidden;
    display: flex;
`;

export const Card = styled.div`
    position: relative;
    opacity: ${props => props.inView ? '1' : '0'};
    transform: translate(${props => props.inView ? '0,0' : '0px,50px'});
    transition: 0.8s;

    &:hover {
        & ${CardImage} {
            transform: scale(1.1);
        }
    }

    & ${CardImage} {
        width: 100%;
        height: auto;
        transition: 0.2s;
        overflow: hidden;
    }

    & ${CardTitle} {
        margin: ${props => props.isTablet ? '16px 0 0 0' : '24px 0 0 0'};
        color: #02010F;
        font-weight: 500;
        font-size: ${props => props.isTablet ? doubleOptions(props.isMobile,'24px','20px') : '32px'};
        line-height: ${props => props.isTablet ? doubleOptions(props.isMobile,'36px','30px') : '48px'};
    }

    & ${CardDescription} {
        color: #46454F;
        font-weight: 400;
        font-size: 16px;
        line-height: 28.8px;
        margin: 0;
    }
`;