import React from 'react'
import Button from '../../../components/Button/Button';
import { DarkText } from '../../../styles/common';
import * as Styled from './styles';
import useMobile from '../../../helpers/hooks/useMobile';
import useTablet from '../../../helpers/hooks/useTablet';
import { useInView } from 'react-intersection-observer';
import {ReactComponent as Arrow} from '../../../assets/images/arrow.svg';
import Spline from '@splinetool/react-spline';


export default function HeroSection({setIsSplineLoaded}) {

	const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
	const isTablet = useTablet();

	function splineToRender () {
		function onSplineLoaded () {
			setTimeout(()=>{
				setIsSplineLoaded(true);
			}, 500)
		}
	
		if (isMobile) {
			return (
				<Spline
					className='spline'
					scene='https://prod.spline.design/AZBMoP5RkOwjhTBD/scene.splinecode'
					onLoad={onSplineLoaded}
				/>
			)
		} else if (isTablet) {
			return (
				<Spline
					className='spline'
					scene='https://prod.spline.design/EdCm6mm6-vR5F2qp/scene.splinecode'
					onLoad={onSplineLoaded}
				/>

			)
		} else {
			return (
				<Spline
					className='spline'
					scene='https://prod.spline.design/GwtQgw9VHxDXUExf/scene.splinecode'
					onLoad={onSplineLoaded}
				/>
			)
		}
	}
	return (
		<Styled.HeroSectionContainer
			isTablet={isTablet}
			isMobile={isMobile}
			id='hero'
			ref={ref}
			inView={inView}
		>
			<Styled.MainContent>
				<Styled.HeroSection>
					<Styled.Title >Delegate UX/UI design and web development</Styled.Title>
					<DarkText>Outsource your web development and UX/UI tasks to professionals and enjoy the process</DarkText>
					<Styled.Link href='#contact'><Button className='hero-button' isMobile={isMobile}>Contact us <Arrow/></Button></Styled.Link>

				</Styled.HeroSection >
				{splineToRender()}
			</Styled.MainContent>
		</Styled.HeroSectionContainer>

		
	)
}
