import React, { useEffect } from 'react';
import BlogSection from '../_sections/BlogSection';
import ClientsSection from '../_sections/ClientsSection';
import ContactSection from '../_sections/ContactSection';
import CTASection from '../_sections/CTASection';
import HeroSection from '../_sections/HeroSection';
import PortfolioSection from '../_sections/PortfolioSection';
import ServicesSection from '../_sections/ServicesSection';
import TestimonialsSection from '../_sections/TestimonialsSection';
import * as Styled from './styles';
import setLoaderStatus from '../../helpers/functions/setLoaderStatus';
import { useState } from 'react';

export default function Home({onMutation}) {
    const [isSplineloaded, setIsSplineLoaded] = useState(false);
    
    useEffect(()=> {
        setLoaderStatus(isSplineloaded);
        
        return setLoaderStatus(false);
    },[isSplineloaded])
    useEffect(()=> {
        onMutation();
        
        // eslint-disable-next-line react-hooks/exhaustive-deps
    },[])

    return (
        <Styled.Home>
            <HeroSection setIsSplineLoaded={setIsSplineLoaded}/>
            <ServicesSection />
            <ClientsSection />
            <TestimonialsSection />
            <CTASection />
            <PortfolioSection />
            <BlogSection />
            <ContactSection />
        </Styled.Home>
    )
}